on-error.log-to-applicationinsights:
@{
            return new JObject(
                new JProperty("EventName", "SummarizeError"),
                new JProperty("SubscriptionId", context.Subscription.Id),
                new JProperty("RequestId", context.Variables.GetValueOrDefault("requestId", "N/A")),
                new JProperty("Timestamp", DateTime.UtcNow),
                new JProperty("ErrorSource", context.LastError.Source),
                new JProperty("ErrorMessage", context.LastError.Message),
                new JProperty("StatusCode", context.Response.StatusCode)
            ).ToString();
        }
